const Redis = require('ioredis');

const body = $input.first().json.body ?? {};
const patientId = $input.first().json.query?.patientId || body.patientId;

if (!patientId) {
  return [{ json: { success: false, error: 'patientId required' } }];
}

const redis = new Redis({ host: 'redis', port: 6379 });

try {
  const exists = await redis.exists(`patient:${patientId}`);
  if (!exists) {
    await redis.quit();
    return [{ json: { success: false, error: 'Patient not found' } }];
  }

  const updates = {};
  if (body.name !== undefined) updates.name = body.name;
  if (body.status !== undefined) updates.status = body.status;

  if (Object.keys(updates).length > 0) {
    await redis.hset(`patient:${patientId}`, updates);
  }

  const patient = await redis.hgetall(`patient:${patientId}`);
  await redis.quit();
  return [{ json: { success: true, patientId, ...patient, deviceId: patient.deviceId || null } }];
} catch (err) {
  await redis.quit().catch(() => {});
  throw err;
}
